  1→#!/usr/bin/env bun
  2→
  3→/**
  4→ * Ralph Loop - Automated Claude Code Task Executor
  5→ *
  6→ * Based on Geoffrey Huntley's Ralph Wiggum technique:
  7→ * - Fresh context per iteration (new Claude instance each time)
  8→ * - Memory persists through files only (git, progress.txt)
  9→ * - One task per iteration
 10→ * - Completion signal terminates loop
 11→ *
 12→ * Uses Claude CLI's --output-format stream-json for real-time streaming.
 13→ *
 14→ * @see https://ghuntley.com/ralph/
 15→ */
 16→
 17→import { appendFileSync, writeFileSync } from 'node:fs';
 18→import { chalk } from 'zx';
 19→
 20→const ANSI_REGEX = /\x1B\[[0-9;]*m/g;
 21→const stripAnsi = (s: string): string => s.replace(ANSI_REGEX, '');
 22→
 23→function parsePositiveInt(arg: string | undefined, fallback: number): number {
 24→  const parsed = parseInt(arg ?? String(fallback), 10);
 25→  if (isNaN(parsed) || parsed <= 0) {
 26→    console.error(`Error: expected a positive integer, got "${arg}"`);
 27→    process.exit(1);
 28→  }
 29→  return parsed;
 30→}
 31→
 32→const CONFIG = Object.freeze({
 33→  maxIterations: parsePositiveInt(Bun.argv[2], 100),
 34→  delayBetweenIterations: 1_000,
 35→  logFile: './loop.log',
 36→  progressFile: './.claude/progress.txt',
 37→  iterationTimeout: 600_000,
 38→  logFlushInterval: 2_000,
 39→  exitPattern: /RALPH_STATUS:\s*\{[^}]*"exit":\s*true[^}]*\}/,
 40→});
 41→
 42→class LogBuffer {
 43→  private buf: string[] = [];
 44→  private timer: ReturnType<typeof setInterval> | null = null;
 45→
 46→  constructor(
 47→    private readonly path: string,
 48→    flushMs: number,
 49→  ) {
 50→    this.timer = setInterval(() => this.flush(), flushMs);
 51→    if (this.timer && typeof this.timer === 'object' && 'unref' in this.timer) {
 52→      (this.timer as NodeJS.Timeout).unref();
 53→    }
 54→  }
 55→
 56→  write(raw: string): void {
 57→    this.buf.push(stripAnsi(raw));
 58→  }
 59→
 60→  flush(): void {
 61→    if (this.buf.length === 0) return;
 62→    const chunk = this.buf.join('');
 63→    this.buf.length = 0;
 64→    try {
 65→      appendFileSync(this.path, chunk);
 66→    } catch (err) {
 67→      console.error(`[LogBuffer] write failed: ${err}`);
 68→    }
 69→  }
 70→
 71→  dispose(): void {
 72→    if (this.timer) clearInterval(this.timer);
 73→    this.flush();
 74→  }
 75→}
 76→
 77→const logBuffer = new LogBuffer(CONFIG.logFile, CONFIG.logFlushInterval);
 78→
 79→type Color = 'green' | 'yellow' | 'red' | 'blue' | 'blackBright';
 80→
 81→function print(message: string, color?: Color): void {
 82→  const colored = color ? chalk[color](message) : message;
 83→  process.stdout.write(colored);
 84→  logBuffer.write(message);
 85→}
 86→
 87→function println(message = '', color?: Color): void {
 88→  const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);
 89→  print(`[${ts}] ${message}\n`, color);
 90→}
 91→
 92→function syslog(message = '', color?: Color): void {
 93→  println(`‣ ${message}`, color);
 94→}
 95→
 96→const TASK_PROMPT = `Read \`./.claude/progress.txt\`, pick the most important pending tasks, execute it, update the file, commit, and stop.
 97→
 98→'./.claude/progress.txt' is:
 99→- your persistent memory.
100→- Important errors must be registered in order to avoid expending tokens again.
101→- Never run tasks not registered in it.
102→- Register new tasks if needed, respecting the current structure.
103→
104→WORKFLOW:
105→1. Read ./.claude/progress.txt and identify the most important pending task;
106→2. If NO pending tasks exist, signal completion (see OUTPUT STATUS below) and stop
107→3. If there are tasks, mark it as IN_PROGRESS and then sequentially run:
108→   b. Execute task (respecting current project structure and ./.claude/STYLE_GUIDE.md)
109→   c. Launch 1 review agents to deeply review the work, giving
110→      the entire context of the task, simulating pull request.
111→   d. Review output and consider improvements
112→   e. Implement corrections if needed
113→   f. Update progress.txt marking task as completed
114→   g. Commit task changes (not include unrelated code)
115→   h. Output status block (see below)
116→   i. Stop
117→
118→- Nenhuma tarefa deve ser considerada completa sem testar com Playwright MVP 
119→  e tirar screenshots para visualização e visualizar.
120→  
121→OUTPUT STATUS (REQUIRED at end of EVERY response):
122→You MUST output this exact format at the END of your response:
123→
124→RALPH_STATUS: { "exit": <true if ALL tasks done, false otherwise>, "task": "<completed task name>", "remaining": <number of pending tasks> }
125→
126→Examples:
127→- Task completed but more remain: RALPH_STATUS: { "exit": false, "task": "Create usePoints hook", "remaining": 5 }
128→- ALL tasks completed: RALPH_STATUS: { "exit": true, "task": "Delete Redux files", "remaining": 0 }
129→
130→CRITICAL (THINK BEFORE ACTING):
131→1. The FIRST thing you MUST do is write your understanding of each WORKFLOW statement
132→2. The SECOND thing you MUST do is write your understanding of the work in progress described in progress.txt
133→3. Only AFTER completing steps 1 and 2, proceed with the task execution
134→4. If more work is necessary, add a new task to the file, set "exit": false, and Stop
135→5. Only set "exit": true when ALL tasks in progress.txt are completed
136→6. For @semparar/* packages, read the real js code because some types are not updated correctly.
137→7. Never remove tasks, unless to update status;
138→`;
139→
140→interface ContentBlock {
141→  type: 'text' | 'tool_use' | 'tool_result';
142→  text?: string;
143→  name?: string;
144→  input?: unknown;
145→  content?:
146→    | string
147→    | Array<{
148→        type: string;
149→        text?: string;
150→      }>;
151→}
152→
153→interface StreamMessage {
154→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
155→  subtype?: string;
156→  role?: 'assistant' | 'user';
157→  event?: {
158→    type: string;
159→    delta?: {
160→      type: string;
161→      text?: string;
162→    };
163→  };
164→  result?: string;
165→  message?: {
166→    role?: string;
167→    content?: ContentBlock[];
168→  };
169→  content?: ContentBlock[];
170→}
171→
172→interface RalphStatus {
173→  exit: boolean;
174→  task: string;
175→  remaining: number;
176→}
177→
178→function parseRalphStatus(output: string): RalphStatus | null {
179→  const marker = output.lastIndexOf('RALPH_STATUS:');
180→  if (marker === -1) return null;
181→
182→  const jsonStart = output.indexOf('{', marker);
183→  if (jsonStart === -1) return null;
184→
185→  let depth = 0;
186→  for (let i = jsonStart; i < output.length; i++) {
187→    if (output[i] === '{') depth++;
188→    if (output[i] === '}') depth--;
189→    if (depth === 0) {
190→      try {
191→        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
192→        if (typeof parsed.exit === 'boolean') {
193→          return parsed as RalphStatus;
194→        }
195→      } catch {}
196→      return null;
197→    }
198→  }
199→  return null;
200→}
201→
202→let currentProc: ReturnType<typeof Bun.spawn> | null = null;
203→
204→function killCurrentProc(): void {
205→  if (!currentProc) return;
206→  try {
207→    currentProc.kill();
208→  } catch {}
209→}
210→
211→async function checkDependencies(): Promise<void> {
212→  const result = await Bun.$`which claude`.quiet().nothrow();
213→  if (result.exitCode !== 0) {
214→    syslog("ERROR: 'claude' CLI not found. Install Claude Code.", 'red');
215→    process.exit(1);
216→  }
217→
218→  if (!(await Bun.file(CONFIG.progressFile).exists())) {
219→    syslog(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
220→    process.exit(1);
221→  }
222→}
223→
224→interface IterationResult {
225→  output: string;
226→  exitCode: number;
227→  timedOut: boolean;
228→}
229→
230→async function runIteration(): Promise<IterationResult> {
231→  syslog('Executing Claude Code...');
232→
233→  const proc = Bun.spawn(
234→    [
235→      'claude',
236→      '-p',
237→      TASK_PROMPT,
238→      '--verbose',
239→      '--debug',
240→      '--dangerously-skip-permissions',
241→      '--output-format',
242→      'stream-json',
243→      '--include-partial-messages',
244→      '--model=opus',
245→    ],
246→    {
247→      cwd: process.cwd(),
248→      env: process.env,
249→      stdout: 'pipe',
250→      stderr: 'inherit',
251→    },
252→  );
253→
254→  currentProc = proc;
255→
256→  const chunks: string[] = [];
257→  let timedOut = false;
258→  const decoder = new TextDecoder();
259→  let buffer = '';
260→  let blockHasContent = false;
261→
262→  const timeoutId = setTimeout(() => {
263→    timedOut = true;
264→    syslog('Iteration timeout reached. Killing process...', 'yellow');
265→    killCurrentProc();
266→  }, CONFIG.iterationTimeout);
267→
268→  const reader = proc.stdout.getReader();
269→
270→  try {
271→    while (true) {
272→      const { done, value } = await reader.read();
273→      if (done) break;
274→
275→      buffer += decoder.decode(value, { stream: true });
276→
277→      const lines = buffer.split('\n');
278→      buffer = lines.pop() || '';
279→
280→      for (const line of lines) {
281→        if (!line.trim()) continue;
282→
283→        let msg: StreamMessage;
284→        try {
285→          msg = JSON.parse(line);
286→        } catch {
287→          continue;
288→        }
289→
290→        if (msg.type === 'stream_event') {
291→          const evt = msg.event;
292→          if (!evt) continue;
293→
294→          if (evt.type === 'content_block_start') {
295→            blockHasContent = false;
296→          } else if (evt.type === 'content_block_delta') {
297→            const text = evt.delta?.text;
298→            if (text) {
299→              print(text);
300→              chunks.push(text);
301→              blockHasContent = true;
302→            }
303→          } else if (evt.type === 'content_block_stop' && blockHasContent) {
304→            print('\n');
305→            chunks.push('\n');
306→            blockHasContent = false;
307→          }
308→          continue;
309→        }
310→
311→        if (msg.type === 'assistant' || msg.type === 'message') {
312→          // Content already streamed via content_block_delta events.
313→          // Only print here as fallback if no streaming occurred.
314→          const blocks = msg.message?.content ?? msg.content;
315→          if (!Array.isArray(blocks)) continue;
316→
317→          for (const block of blocks) {
318→            if (block.type === 'text' && block.text && chunks.length === 0) {
319→              print(block.text);
320→              chunks.push(block.text);
321→              print('\n');
322→              chunks.push('\n');
323→            }
324→          }
325→          continue;
326→        }
327→
328→        if (msg.type === 'user') {
329→          const blocks = msg.message?.content ?? msg.content;
330→          if (!Array.isArray(blocks)) continue;
331→
332→          for (const block of blocks) {
333→            //
334→            // Handling tool result
335→            if (block.type === 'tool_result' && block.content) {
336→              const rawContent =
337→                typeof block.content === 'string'
338→                  ? block.content
339→                  : block.content
340→                      .map(c => c.text ?? '')
341→                      .filter(Boolean)
342→                      .join('\n');
343→
344→              if (!rawContent) continue;
345→
346→              let trimmed = rawContent.trim().slice(0, 320);
347→
348→              const toolResult =
349→                trimmed && trimmed !== rawContent
350→                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
351→                  : rawContent;
352→
353→              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
354→              chunks.push('\n', rawContent, '\n');
355→            }
356→          }
357→          continue;
358→        }
359→
360→        if (msg.type === 'result' && msg.result) {
361→          if (chunks.length === 0) {
362→            chunks.push(msg.result);
363→          }
364→        }
365→      }
366→    }
367→
368→    if (buffer.trim()) {
369→      try {
370→        const msg: StreamMessage = JSON.parse(buffer);
371→        if (msg.type === 'result' && msg.result && chunks.length === 0) {
372→          chunks.push(msg.result);
373→        }
374→      } catch {}
375→    }
376→  } finally {
377→    clearTimeout(timeoutId);
378→    reader.releaseLock();
379→    currentProc = null;
380→    logBuffer.flush();
381→  }
382→
383→  const output = chunks.join('');
384→
385→  if (timedOut) {
386→    return {
387→      output,
388→      exitCode: 124,
389→      timedOut: true,
390→    };
391→  }
392→
393→  const exitCode = await proc.exited;
394→  println();
395→  return {
396→    output,
397→    exitCode,
398→    timedOut: false,
399→  };
400→}
401→
402→function printHeader(): void {
403→  println();
404→  println('==========================================', 'blue');
405→  println('   Ralph Loop - Bun.js Edition', 'blue');
406→  println('==========================================', 'blue');
407→  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
408→  println(`Log file:       ${chalk.yellow(CONFIG.logFile)}`);
409→  println(
410→    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
411→  );
412→  println(
413→    `Iter timeout:   ${chalk.yellow(`${CONFIG.iterationTimeout / 60_000}min`)}`,
414→  );
415→  println();
416→}
417→
418→async function main(): Promise<void> {
419→  let cleanupCalled = false;
420→
421→  const cleanup = (signal: string) => {
422→    if (cleanupCalled) return;
423→    cleanupCalled = true;
424→    println();
425→    syslog(`Interrupted by ${signal}. Cleaning up...`);
426→    killCurrentProc();
427→    logBuffer.dispose();
428→    process.exit(signal === 'SIGINT' ? 130 : 143);
429→  };
430→
431→  process.on('SIGINT', () => cleanup('SIGINT'));
432→  process.on('SIGTERM', () => cleanup('SIGTERM'));
433→
434→  await checkDependencies();
435→
436→  writeFileSync(CONFIG.logFile, '');
437→
438→  printHeader();
439→  syslog('Starting automated task loop...');
440→
441→  let consecutiveFailures = 0;
442→  const MAX_CONSECUTIVE_FAILURES = 3;
443→
444→  for (let iteration = 1; iteration <= CONFIG.maxIterations; iteration++) {
445→    println();
446→    println('==========================================', 'green');
447→    syslog(`Iteration #${iteration} / ${CONFIG.maxIterations}`, 'green');
448→    println('==========================================', 'green');
449→    println();
450→
451→    const { output, exitCode, timedOut } = await runIteration();
452→
453→    if (exitCode === 0) {
454→      syslog('Claude Code completed successfully', 'green');
455→      consecutiveFailures = 0;
456→    } else {
457→      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
458→      consecutiveFailures++;
459→    }
460→
461→    if (consecutiveFailures >= MAX_CONSECUTIVE_FAILURES) {
462→      println();
463→      println('==========================================', 'red');
464→      syslog(
465→        `${MAX_CONSECUTIVE_FAILURES} consecutive failures — aborting loop`,
466→        'red',
467→      );
468→      println('==========================================', 'red');
469→      logBuffer.dispose();
470→      process.exit(1);
471→    }
472→
473→    const status = parseRalphStatus(output);
474→
475→    if (status?.exit) {
476→      println();
477→      println('==========================================', 'green');
478→      syslog('ALL TASKS COMPLETED!', 'green');
479→      syslog(`Final task:      ${status.task}`, 'green');
480→      syslog(`Remaining:       ${status.remaining}`, 'green');
481→      syslog(`Total iterations: ${iteration}`, 'green');
482→      println('==========================================', 'green');
483→      logBuffer.dispose();
484→      process.exit(0);
485→    }
486→
487→    if (status) {
488→      syslog(
489→        `Task done: "${status.task}" — ${status.remaining} remaining`,
490→        'blue',
491→      );
492→    } else if (!timedOut && exitCode === 0) {
493→      syslog(
494→        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
495→        'yellow',
496→      );
497→    }
498→
499→    if (iteration < CONFIG.maxIterations) {
500→      const delaySec = CONFIG.delayBetweenIterations / 1_000;
501→      println();
502→      syslog(`Waiting ${delaySec}s before next iteration...`);
503→      await Bun.sleep(CONFIG.delayBetweenIterations);
504→    }
505→  }
506→
507→  println();
508→  println('==========================================', 'red');
509→  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
510→  syslog('Loop stopped — tasks may still be pending', 'red');
511→  println('==========================================', 'red');
512→  logBuffer.dispose();
513→  process.exit(1);
514→}
515→
516→main();
